  1→import { createHash } from "node:crypto";
  2→import { query } from "../db.js";
  3→import type { LegacySubmission, MapScope, PointEvent, PointEventType, SubmissionCategory, UserProfile } from "../../../shared/types.js";
  4→import { normalizeEmail, normalizePhone } from "../../shared/identifier.js";
  5→import type { StorageStore } from "./types.js";
  6→
  7→const VALID_MAP_SCOPES: ReadonlySet<MapScope> = new Set(["bonamoussadi", "cameroon", "global"]);
  8→let phoneColumnState: "unknown" | "present" | "missing" = "unknown";
  9→
 10→function normalizeUserId(input: string): string {
 11→  return input.toLowerCase().trim();
 12→}
 13→
 14→function normalizeMapScope(input: unknown): MapScope {
 15→  if (typeof input !== "string") return "bonamoussadi";
 16→  const normalized = input.trim().toLowerCase() as MapScope;
 17→  if (!VALID_MAP_SCOPES.has(normalized)) return "bonamoussadi";
 18→  return normalized;
 19→}
 20→
 21→function parseXp(input: unknown): number {
 22→  const value = typeof input === "number" ? input : Number(input);
 23→  if (!Number.isFinite(value)) return 0;
 24→  return Math.max(0, Math.round(value));
 25→}
 26→
 27→function isUuid(input: string): boolean {
 28→  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(input);
 29→}
 30→
 31→function deterministicUuid(seed: string): string {
 32→  const hex = createHash("sha1").update(seed).digest("hex").slice(0, 32).split("");
 33→  hex[12] = "5";
 34→  const variant = parseInt(hex[16], 16);
 35→  hex[16] = ((variant & 0x3) | 0x8).toString(16);
 36→  return `${hex.slice(0, 8).join("")}-${hex.slice(8, 12).join("")}-${hex.slice(12, 16).join("")}-${hex.slice(16, 20).join("")}-${hex.slice(20, 32).join("")}`;
 37→}
 38→
 39→function normalizeEventId(input: string): string {
 40→  const trimmed = input.trim();
 41→  if (isUuid(trimmed)) return trimmed.toLowerCase();
 42→  return deterministicUuid(`event:${trimmed}`);
 43→}
 44→
 45→function normalizeCreatedAt(input: unknown): string {
 46→  if (typeof input === "string") {
 47→    const parsed = new Date(input);
 48→    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
 49→  }
 50→  return new Date().toISOString();
 51→}
 52→
 53→function parseCategory(input: unknown): SubmissionCategory {
 54→  if (input === "pharmacy" || input === "fuel_station" || input === "mobile_money") return input;
 55→  return "mobile_money";
 56→}
 57→
 58→function parseEventType(input: unknown): PointEventType {
 59→  if (input === "CREATE_EVENT" || input === "ENRICH_EVENT") return input;
 60→  return "CREATE_EVENT";
 61→}
 62→
 63→function parseLocation(input: unknown): { latitude: number; longitude: number } | null {
 64→  const raw = input as { latitude?: unknown; longitude?: unknown };
 65→  const latitude = typeof raw?.latitude === "number" ? raw.latitude : Number(raw?.latitude);
 66→  const longitude = typeof raw?.longitude === "number" ? raw.longitude : Number(raw?.longitude);
 67→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 68→  return { latitude, longitude };
 69→}
 70→
 71→function rowToUserProfile(row: Record<string, unknown>): UserProfile {
 72→  const email = typeof row.email === "string" && row.email.trim() ? row.email.toLowerCase().trim() : null;
 73→  const phone = typeof row.phone === "string" && row.phone.trim() ? row.phone.trim() : null;
 74→  return {
 75→    id: String(row.id ?? "").toLowerCase().trim(),
 76→    email,
 77→    phone,
 78→    name: typeof row.name === "string" ? row.name : "",
 79→    image: typeof row.image === "string" ? row.image : "",
 80→    occupation: typeof row.occupation === "string" ? row.occupation : "",
 81→    XP: parseXp(row.xp),
 82→    passwordHash: typeof row.password_hash === "string" ? row.password_hash : undefined,
 83→    isAdmin: Boolean(row.is_admin),
 84→    mapScope: normalizeMapScope(row.map_scope),
 85→  };
 86→}
 87→
 88→function isMissingPhoneColumnError(error: unknown): boolean {
 89→  if (!(error instanceof Error)) return false;
 90→  const pgError = error as Error & { code?: string };
 91→  const message = error.message.toLowerCase();
 92→  return pgError.code === "42703" && message.includes("phone");
 93→}
