 95→async function getUserProfileLegacy(id: string): Promise<UserProfile | null> {
 96→  const result = await query<Record<string, unknown>>(
 97→    `
 98→      select id, email, name, image, occupation, xp, password_hash, is_admin, map_scope
 99→      from user_profiles
100→      where id = $1
101→      limit 1
102→    `,
103→    [id],
104→  );
105→
106→  const row = result.rows[0];
107→  if (!row) return null;
108→  return rowToUserProfile(row);
109→}
110→
111→function rowToPointEvent(row: Record<string, unknown>): PointEvent {
112→  const details = row.details && typeof row.details === "object" ? (row.details as PointEvent["details"]) : {};
113→
114→  return {
115→    id: String(row.id),
116→    pointId: String(row.point_id ?? ""),
117→    eventType: parseEventType(row.event_type),
118→    userId: String(row.user_id ?? "").toLowerCase().trim(),
119→    category: parseCategory(row.category),
120→    location: {
121→      latitude: typeof row.latitude === "number" ? row.latitude : Number(row.latitude),
122→      longitude: typeof row.longitude === "number" ? row.longitude : Number(row.longitude),
123→    },
124→    details,
125→    photoUrl: typeof row.photo_url === "string" ? row.photo_url : undefined,
126→    createdAt: normalizeCreatedAt(row.created_at),
127→    source: typeof row.source === "string" ? row.source : undefined,
128→    externalId: typeof row.external_id === "string" ? row.external_id : undefined,
129→  };
130→}
