301→async function insertPointEvent(event: PointEvent): Promise<void> {
302→  const id = normalizeEventId(event.id);
303→  const pointId = typeof event.pointId === "string" && event.pointId.trim() ? event.pointId.trim() : id;
304→  const eventType = parseEventType(event.eventType);
305→  const userId = normalizeUserId(event.userId || "unknown");
306→  const category = parseCategory(event.category);
307→  const location = parseLocation(event.location);
308→  if (!location) throw new Error("Invalid point event location");
309→  const details = event.details && typeof event.details === "object" ? event.details : {};
310→  const photoUrl = typeof event.photoUrl === "string" ? event.photoUrl : null;
311→  const createdAt = normalizeCreatedAt(event.createdAt);
312→  const source = typeof event.source === "string" ? event.source : null;
313→  const externalId = typeof event.externalId === "string" ? event.externalId : null;
314→
315→  await query(
316→    `
317→      insert into point_events (id, point_id, event_type, user_id, category, latitude, longitude, details, photo_url, created_at, source, external_id)
318→      values ($1::uuid, $2, $3, $4, $5, $6, $7, $8::jsonb, $9, $10::timestamptz, $11, $12)
319→      on conflict (id) do update
320→      set
321→        point_id = excluded.point_id,
322→        event_type = excluded.event_type,
323→        user_id = excluded.user_id,
324→        category = excluded.category,
325→        latitude = excluded.latitude,
326→        longitude = excluded.longitude,
327→        details = excluded.details,
328→        photo_url = excluded.photo_url,
329→        created_at = excluded.created_at,
330→        source = excluded.source,
331→        external_id = excluded.external_id
332→    `,
333→    [id, pointId, eventType, userId, category, location.latitude, location.longitude, JSON.stringify(details), photoUrl, createdAt, source, externalId],
334→  );
335→}
336→
337→async function deletePointEvent(eventId: string): Promise<boolean> {
338→  const normalizedId = normalizeEventId(eventId);
339→  const result = await query(
340→    `
341→      delete from point_events
342→      where id = $1::uuid
343→    `,
344→    [normalizedId],
345→  );
346→  return result.rowCount > 0;
347→}
348→
349→async function bulkUpsertPointEvents(events: PointEvent[]): Promise<void> {
350→  if (!events.length) return;
351→
352→  await query("begin");
353→  try {
354→    for (const event of events) {
355→      await insertPointEvent(event);
356→    }
357→    await query("commit");
358→  } catch (error) {
359→    await query("rollback");
360→    throw error;
361→  }
362→}
