 13→const ENRICHABLE_FIELDS: GapRules = {
 14→  pharmacy: ["openingHours", "isOpenNow", "isOnDuty"],
 15→  mobile_money: ["merchantIdByProvider", "paymentMethods", "openingHours", "providers"],
 16→  fuel_station: ["fuelTypes", "pricesByFuel", "quality", "paymentMethods", "openingHours", "hasFuelAvailable"],
 17→};
 18→
 19→const CREATE_REQUIRED_FIELDS: GapRules = {
 20→  pharmacy: ["name", "isOpenNow"],
 21→  mobile_money: ["providers"],
 22→  fuel_station: ["name", "hasFuelAvailable"],
 23→};
 24→
 25→function hasValue(input: unknown): boolean {
 26→  if (typeof input === "string") return Boolean(input.trim());
 27→  if (typeof input === "number") return Number.isFinite(input);
 28→  if (typeof input === "boolean") return true;
 29→  if (Array.isArray(input)) return input.length > 0;
 30→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 31→  return false;
 32→}
 33→
 34→function trimString(input: unknown): string | undefined {
 35→  if (typeof input !== "string") return undefined;
 36→  const trimmed = input.trim();
 37→  return trimmed || undefined;
 38→}
 39→
 40→function normalizeBoolean(input: unknown): boolean | undefined {
 41→  if (typeof input === "boolean") return input;
 42→  if (typeof input === "number") {
 43→    if (input === 1) return true;
 44→    if (input === 0) return false;
 45→    return undefined;
 46→  }
 47→  if (typeof input !== "string") return undefined;
 48→  const normalized = input.trim().toLowerCase();
 49→  if (!normalized) return undefined;
 50→  if (["true", "yes", "y", "1", "open", "available", "oui"].includes(normalized)) return true;
 51→  if (["false", "no", "n", "0", "closed", "unavailable", "non"].includes(normalized)) return false;
 52→  return undefined;
 53→}
 54→
 55→function normalizeProviders(input: unknown): string[] | undefined {
 56→  if (Array.isArray(input)) {
 57→    const list = input
 58→      .map((value) => trimString(value))
 59→      .filter((value): value is string => Boolean(value));
 60→    return list.length ? Array.from(new Set(list)) : undefined;
 61→  }
 62→  const single = trimString(input);
 63→  return single ? [single] : undefined;
 64→}
 65→
 66→function normalizeDetailsForCategory(category: SubmissionCategory, raw: SubmissionDetails): SubmissionDetails {
 67→  const details: SubmissionDetails = { ...raw };
 68→  const name = trimString(details.name) ?? trimString(details.siteName);
 69→  if (name) {
 70→    details.name = name;
 71→    details.siteName = name;
 72→  }
 73→
 74→  const openingHours = trimString((details as Record<string, unknown>).opening_hours) ?? trimString(details.openingHours);
 75→  if (openingHours) details.openingHours = openingHours;
 76→
 77→  if (category === "mobile_money") {
 78→    const providers = normalizeProviders(details.providers ?? details.provider);
 79→    if (providers) details.providers = providers;
 80→    const cashThreshold =
 81→      normalizeBoolean(details.hasMin50000XafAvailable) ??
 82→      normalizeBoolean(details.hasCashAvailable) ??
 83→      (typeof details.availability === "string" ? !details.availability.toLowerCase().includes("out") : undefined);
 84→    if (typeof cashThreshold === "boolean") {
 85→      details.hasMin50000XafAvailable = cashThreshold;
 86→    }
 87→    if ("hasCashAvailable" in details) {
 88→      delete details.hasCashAvailable;
 89→    }
 90→    if (details.merchantId && providers?.length && !details.merchantIdByProvider) {
 91→      details.merchantIdByProvider = { [providers[0]]: details.merchantId };
 92→    }
 93→  }
 94→
 95→  if (category === "fuel_station") {
 96→    const fuelType = trimString(details.fuelType);
 97→    if (fuelType && !details.fuelTypes?.length) details.fuelTypes = [fuelType];
 98→    const parsedPrice =
 99→      typeof details.fuelPrice === "number"
100→        ? details.fuelPrice
101→        : typeof details.price === "number"
102→          ? details.price
103→          : undefined;
104→    if (typeof details.hasFuelAvailable !== "boolean" && typeof details.availability === "string") {
105→      details.hasFuelAvailable = !details.availability.toLowerCase().includes("out");
106→    }
107→    if (parsedPrice !== undefined) {
108→      const priceKey = fuelType ?? "super";
109→      details.pricesByFuel = { ...(details.pricesByFuel ?? {}), [priceKey]: parsedPrice };
110→      details.fuelPrice = parsedPrice;
111→      details.price = parsedPrice;
112→    }
113→  }
114→
115→  if (category === "pharmacy" && typeof details.isOpenNow !== "boolean" && typeof details.availability === "string") {
116→    const normalized = details.availability.toLowerCase();
117→    details.isOpenNow = !normalized.includes("out") && !normalized.includes("closed");
118→  }
119→
120→  if (category === "pharmacy") {
121→    const raw = details as Record<string, unknown>;
122→    const isOnDuty = normalizeBoolean(raw.isOnDuty ?? raw.isOnCall ?? raw.onDuty ?? raw.pharmacyDeGarde);
123→    if (typeof isOnDuty === "boolean") details.isOnDuty = isOnDuty;
124→
125→    if (typeof details.isOnDuty !== "boolean" && typeof details.availability === "string") {
126→      const normalized = details.availability.toLowerCase();
127→      if (normalized.includes("on-call") || normalized.includes("on call") || normalized.includes("garde")) {
128→        details.isOnDuty = true;
129→      }
130→    }
131→  }
132→
133→  return details;
134→}
135→
136→function mergeDetails(base: SubmissionDetails, incoming: SubmissionDetails): SubmissionDetails {
137→  const merged: SubmissionDetails = { ...base };
138→  const entries = Object.entries(incoming) as Array<[string, unknown]>;
139→  for (const [key, value] of entries) {
140→    if (!hasValue(value)) continue;
141→    if (Array.isArray(value)) {
142→      merged[key] = value;
143→      continue;
144→    }
145→    if (typeof value === "object" && value !== null && !Array.isArray(value)) {
146→      const prev = merged[key];
147→      if (typeof prev === "object" && prev !== null && !Array.isArray(prev)) {
148→        merged[key] = { ...(prev as Record<string, unknown>), ...(value as Record<string, unknown>) };
149→      } else {
150→        merged[key] = value;
151→      }
152→      continue;
153→    }
154→    merged[key] = value;
155→  }
156→  return merged;
157→}
158→
159→export function listMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
160→  const normalized = normalizeDetailsForCategory(category, details);
161→  return ENRICHABLE_FIELDS[category].filter((field) => !hasValue(normalized[field]));
162→}
163→
164→export function listCreateMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
165→  const normalized = normalizeDetailsForCategory(category, details);
166→  return CREATE_REQUIRED_FIELDS[category].filter((field) => !hasValue(normalized[field]));
167→}
168→
169→export function isEnrichFieldAllowed(category: SubmissionCategory, field: string): boolean {
170→  const canonicalField =
171→    field === "merchantId"
172→      ? "merchantIdByProvider"
173→      : field === "hasCashAvailable"
174→        ? "hasMin50000XafAvailable"
175→      : field === "hours"
176→        ? "openingHours"
177→        : field === "isOnCall" || field === "onDuty"
178→          ? "isOnDuty"
179→          : field;
180→  return ENRICHABLE_FIELDS[category].includes(canonicalField);
181→}
