382→export async function GET(request: Request): Promise<Response> {
383→  const auth = await requireUser(request);
384→  const authContext = toSubmissionAuthContext(auth);
385→  const url = new URL(request.url);
386→  const view = url.searchParams.get("view");
387→  const lat = url.searchParams.get("lat");
388→  const lng = url.searchParams.get("lng");
389→  const radius = url.searchParams.get("radius");
390→  const requestedScope = normalizeMapScope(url.searchParams.get("scope"));
391→  const canUseExpandedScope = requestedScope !== "bonamoussadi";
392→  if (canUseExpandedScope && !authContext) return errorResponse("Unauthorized", 401);
393→  if (canUseExpandedScope && !authContext.isAdmin) return errorResponse("Forbidden", 403);
394→  const effectiveScope = canUseExpandedScope ? requestedScope : "bonamoussadi";
395→  const canUsePublicCache = !authContext && !canUseExpandedScope;
396→
397→  try {
398→    const allEvents = await buildCombinedEvents();
399→    const scopedEvents = allEvents.filter((event) => {
400→      if (effectiveScope === "global") return true;
401→      if (effectiveScope === "cameroon") return isWithinCameroon(event.location);
402→      return isWithinBonamoussadi(event.location);
403→    });
404→
405→    if (view === "events") {
406→      if (!authContext) {
407→        return jsonResponse(redactEventUserIds(scopedEvents), {
408→          status: 200,
409→          headers: {
410→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
411→          },
412→        });
413→      }
414→      const responseEvents = filterEventsForViewer(scopedEvents, authContext);
415→      return jsonResponse(responseEvents, { status: 200 });
416→    }
417→
418→    if (view === "admin_events") {
419→      const adminAccess = resolveAdminViewAccess(authContext);
420→      if (adminAccess === "unauthorized") return errorResponse("Unauthorized", 401);
421→      if (adminAccess === "forbidden") return errorResponse("Forbidden", 403);
422→      const adminEvents = await buildAdminSubmissionEvents(scopedEvents);
423→      return jsonResponse(adminEvents, { status: 200 });
424→    }
425→
426→    let projected = projectPointsFromEvents(scopedEvents);
427→
428→    if (lat && lng && radius) {
429→      const latitude = Number(lat);
430→      const longitude = Number(lng);
431→      const radiusKm = Number(radius);
432→      if (Number.isFinite(latitude) && Number.isFinite(longitude) && Number.isFinite(radiusKm)) {
433→        projected = projected.filter((point) => haversineKm(point.location, { latitude, longitude }) <= radiusKm);
434→      }
435→    }
436→
437→    return jsonResponse(projected, {
438→      status: 200,
439→      headers: canUsePublicCache
440→        ? {
441→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
442→          }
443→        : undefined,
444→    });
445→  } catch (error) {
446→    if (isStorageUnavailableError(error)) {
447→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
448→    }
449→    throw error;
450→  }
451→}
