 1→export function jsonResponse(body: unknown, init: ResponseInit = {}): Response {
 2→  const headers = new Headers(init.headers);
 3→  if (!headers.has("content-type")) {
 4→    headers.set("content-type", "application/json");
 5→  }
 6→  if (!headers.has("cache-control")) {
 7→    headers.set("cache-control", "no-store");
 8→  }
 9→  return new Response(JSON.stringify(body), { ...init, headers });
10→}
11→
12→export function errorResponse(message: string, status: number, options: { code?: string } = {}): Response {
13→  const body: { error: string; code?: string } = { error: message };
14→  if (options.code) body.code = options.code;
15→  return jsonResponse(body, { status });
16→}
