29→  return (
30→    location.latitude >= BONAMOUSSADI_BOUNDS.south &&
31→    location.latitude <= BONAMOUSSADI_BOUNDS.north &&
32→    location.longitude >= BONAMOUSSADI_BOUNDS.west &&
33→    location.longitude <= BONAMOUSSADI_BOUNDS.east
