 80→export async function getLegacySubmissions() {
 81→  if (resolveDriver() === "edge") {
 82→    return await edgeConfigStore.getLegacySubmissions();
 83→  }
 84→  if (shouldUseFallback()) {
 85→    return await edgeFallbackStore.getLegacySubmissions();
 86→  }
 87→  return [];
 88→}
